mapper.select:
SELECT id, user_id as userId, title, category, LEFT(content,200) as summary, accepted_reply_id as acceptedReplyId, view_count as viewCount, reply_count as replyCount, DATE_FORMAT(created_at,'%Y-%m-%d %H:%i') as createdAt FROM forum_post WHERE status = 0 AND user_id = #{userId}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY created_at DESC
